using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Replace with your actual namespace

public class ProductController : Controller
{
    private readonly IReviewRepository _reviewRepo;

    public ProductController(IReviewRepository reviewRepo)
    {
        _reviewRepo = reviewRepo;
    }

    public ActionResult Index(int id)
    {
        var product = _reviewRepo.GetProduct(id);
        if (product == null)
        {
            return HttpNotFound();
        }
        return View(product);
    }

    [ChildActionOnly]
    public PartialViewResult GetReviews(int id)
    {
        var reviews = _reviewRepo.GetReviewsForProduct(id);
        return PartialView("_Reviews", reviews);
    }
}

public class ReviewRepository : IReviewRepository
{
    private readonly YourDbContext _db; // Replace with your actual DbContext

    public ReviewRepository(YourDbContext db)
    {
        _db = db;
    }

    public Product GetProduct(int id)
    {
        return _db.Products.Find(id);
    }

    public IEnumerable<Review> GetReviewsForProduct(int id)
    {
        return _db.Reviews.Where(r => r.ProductId == id).ToList();
    }
}

